/**
 * Test for OKX's SBE (Simple Binary Encoding) orderbook endpoint
 * Note: This test requires a valid instIdCode which must be obtained from OKX API
 * The instIdCode is an integer identifier for each trading pair
 */
function test_fetch_order_book_sbe($exchange, $skipped_properties, $symbol, $inst_id_code) {
    $method = 'fetchOrderBookSbe';
    // Check if the method exists (OKX-specific)
    $exchange_any = $exchange;
    if (!$exchange_any->fetch_order_book_sbe) {
        var_dump('fetchOrderBookSbe is not supported by', $exchange->id);
        return true;
    }
    $orderbook = $exchange->fetch_order_book_sbe($symbol, $inst_id_code);
    test_order_book($exchange, $skipped_properties, $method, $orderbook, $symbol);
    // Additional SBE-specific validations
    // The orderbook should have the standard structure
    var_dump('SBE Orderbook fetched successfully for', $symbol);
    var_dump('Bids:', count($orderbook->bids), 'Asks:', count($orderbook->asks));
    return true;
}
